index 2d7524e8018b..9fb84f8c514b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -14,7 +14,7 @@
 #include "llvm/ADT/SmallBitVector.h"
 #include "llvm/Analysis/CmpInstAnalysis.h"
 #include "llvm/Analysis/FloatingPointPredicateUtils.h"
-#include "llvm/Analysis/InstructionSimplify.h"
+#include "llvm/Analysis/InstructionSimplify.h"\n#include "llvm/Analysis/ValueTracking.h"
 #include "llvm/IR/ConstantRange.h"
 #include "llvm/IR/DerivedTypes.h"
 #include "llvm/IR/Instructions.h"
@@ -196,6 +196,46 @@ static bool decomposeBitTestICmp(Value *Cond, CmpInst::Predicate &Pred,
   Z = ConstantInt::get(X->getType(), Res->C);
   return true;
 }
+/// Compute a ConstantRange representing the set of values of the compared
+/// variable that satisfy the given ICmp. If the ICmp is of the form
+/// (X & Mask) == C where Mask is a negated power of two, compute the
+/// contiguous range [C, C + |Mask|). Otherwise, use makeExactICmpRegion.
+/// Returns None if the range cannot be computed (e.g., non-constant operand).
+static std::optional<ConstantRange>
+computeConstantRangeFromICmp(const ICmpInst *ICmp) {
+  Value *Op0 = ICmp->getOperand(0);
+  Value *Op1 = ICmp->getOperand(1);
+  const APInt *C;
+  // For simplicity, assume constant is on RHS.
+  if (!match(Op1, m_APInt(C))) {
+    // Try swapping.
+    if (!match(Op0, m_APInt(C)))
+      return std::nullopt;
+    std::swap(Op0, Op1);
+  }
+  // Now Op0 is variable, Op1 is constant C.
+  // Check for masked equality pattern.
+  ICmpInst::Predicate Pred = ICmp->getPredicate();
+  if (Pred == ICmpInst::ICMP_EQ) {
+    Value *X;
+    const APInt *Mask;
+    // Match (X & Mask) == C.
+    if (match(Op0, m_And(m_Value(X), m_APInt(Mask)))) {
+      // Only handle masks that are negated power of two (i.e., clear low bits).
+      if (Mask->isNegatedPowerOf2()) {
+        // C must have zero bits where mask has zero bits.
+        if ((*C & ~*Mask) == 0) {
+          // The set of values satisfying (X & Mask) == C is
+          // [C, C + Mask->abs()) because Mask clears low bits.
+          APInt Size = Mask->abs();
+          return ConstantRange(*C, *C + Size);
+        }
+      }
+    }
+  }
+  // For other predicates, use makeExactICmpRegion.
+  return ConstantRange::makeExactICmpRegion(Pred, *C);
+}

 /// Handle (icmp(A & B) ==/!= C) &/| (icmp(A & D) ==/!= E).
 /// Return the pattern classes (from MaskedICmpType) for the left hand side and
@@ -3579,6 +3619,90 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     return Builder.createIsFPClass(X, IsAnd ? FPClassTest::fcNormal
                                             : ~FPClassTest::fcNormal);

+  // Try to fold (icmp Pred X, C) &/| (icmp eq (X & Mask), Val) when Mask is a negated power of two.
+  auto tryFoldMaskedRange = [&](ICmpInst *ICmp1, ICmpInst *ICmp2) -> Value* {
+    ICmpInst::Predicate Pred1 = ICmp1->getPredicate();
+    const APInt *C1, *C2;
+    if (!match(ICmp1->getOperand(1), m_APInt(C1)) ||
+        !match(ICmp2->getOperand(1), m_APInt(C2)))
+      return nullptr;
+    // Determine which is masked equality and which is relational.
+    ICmpInst *ICmpMasked = nullptr, *ICmpRel = nullptr;
+    Value *XMasked = nullptr, *XRel = nullptr;
+    const APInt *Mask = nullptr, *Val = nullptr, *Bound = nullptr;
+    ICmpInst::Predicate RelPred;
+    auto isMaskedEq = [&](ICmpInst::Predicate Pred, Value *Op0, const APInt *C,
+                          Value *&X, const APInt *&Mask, const APInt *&Val) -> bool {
+      if (Pred != ICmpInst::ICMP_EQ)
+        return false;
+      Value *AndOp;
+      const APInt *MaskConst;
+      if (!match(Op0, m_And(m_Value(X), m_NegatedPower2(MaskConst))))
+        return false;
+      // Val must have zeros where Mask has zeros.
+      if ((*C & ~*MaskConst) != 0)
+        return false;
+      Mask = MaskConst;
+      Val = C;
+      return true;
+    };
+    if (isMaskedEq(Pred2, Op2_0, C2, XMasked, Mask, Val) &&
+        ICmpInst::isRelational(Pred1)) {
+      ICmpMasked = ICmp2;
+      ICmpRel = ICmp1;
+      XRel = Op1_0;
+      RelPred = Pred1;
+      Bound = C1;
+    } else if (isMaskedEq(Pred1, Op1_0, C1, XMasked, Mask, Val) &&
+               ICmpInst::isRelational(Pred2)) {
+      ICmpMasked = ICmp1;
+      ICmpRel = ICmp2;
+      XRel = Op2_0;
+      RelPred = Pred2;
+      Bound = C2;
+    } else {
+      return nullptr;
+    }
+    if (XMasked != XRel)
+      return nullptr;
+    // Compute contiguous range of possible values for masked equality.
+    unsigned TrailingOnes = (~*Mask).countTrailingOnes();
+    if (TrailingOnes == 0)
+      return nullptr;
+    APInt Size = APInt::getOneBitSet(Mask->getBitWidth(), TrailingOnes);
+    ConstantRange MaskedRange(*Val, *Val + Size);
+    ConstantRange RelRange = ConstantRange::makeExactICmpRegion(RelPred, *Bound);
+    // Determine subset relationship.
+    if (RelRange.contains(MaskedRange)) {
+      // Masked equality implies relational condition.
+      // For AND, keep masked equality (stronger). For OR, keep relational (weaker).
+      return IsAnd ? ICmp2 : ICmp1;
+    }
+    if (MaskedRange.contains(RelRange)) {
+      // Relational condition implies masked equality.
+      // For AND, keep relational (stronger). For OR, keep masked equality (weaker).
+      return IsAnd ? ICmp1 : ICmp2;
+    }
+    return nullptr;
+  };
+  if (Value *V = tryFoldMaskedRange(LHS, RHS))
+    return V;
+
+  // If one icmp implies the other, we can simplify.
+  const DataLayout &DL = getDataLayout();
+  if (std::optional<bool> Imp = isImpliedCondition(LHS, RHS, DL)) {
+    if (*Imp) {
+      // LHS implies RHS
+      return IsAnd ? LHS : RHS;
+    }
+  }
+  if (std::optional<bool> Imp = isImpliedCondition(RHS, LHS, DL)) {
+    if (*Imp) {
+      // RHS implies LHS
+      return IsAnd ? RHS : LHS;
+    }
+  }
+
   return foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd);
 }

